module top_module (
    input clk,
    input reset,
    output [3:0] count );reg [3:0] invalid_count;

    always @(posedge clk) begin
        if (reset)
            invalid_count <= 4'b0000;
        else
            invalid_count <= invalid_count + 1;
    end

    assign count = invalid_count;

endmodule
